import { optimizeLabelStackWithRegistry } from '../common/utils';
export function optimizeSpans(spans, interactionStart, reactUFOVersion, registry) {
  const updatedSpans = spans.reduce((result, span) => {
    const {
      labelStack,
      type,
      name,
      start,
      end
    } = span;
    if (labelStack && start >= interactionStart) {
      result.push({
        labelStack: optimizeLabelStackWithRegistry([...labelStack, {
          name
        }], reactUFOVersion, registry),
        startTime: Math.round(start),
        endTime: Math.round(end),
        type
      });
    }
    return result;
  }, []);
  return updatedSpans;
}